class Solution:
    def gcdSort(self, nums):
        import math
        n = len(nums)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for i in range(n):
            for j in range(i + 1, n):
                if math.gcd(nums[i], nums[j]) > 1:
                    union(i, j)
        order = sorted(range(n), key=lambda i: nums[i])
        for pos, orig in enumerate(order):
            if find(pos) != find(orig):
                return False
        return True

