var gcdSort = function(nums) {
    const maxVal = Math.max(...nums);
    const spf = new Int32Array(maxVal + 1);
    for (let i = 0; i <= maxVal; i++) spf[i] = i;
    for (let i = 2; i * i <= maxVal; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j <= maxVal; j += i) {
                if (spf[j] === j) spf[j] = i;
            }
        }
    }
    const parent = new Int32Array(maxVal + 1);
    for (let i = 0; i <= maxVal; i++) parent[i] = i;
    const find = (x) => {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    };
    const union = (a, b) => {
        const ra = find(a), rb = find(b);
        if (ra !== rb) parent[ra] = rb;
    };
    const seen = new Set(nums);
    for (const v of seen) {
        let x = v;
        while (x > 1) {
            const p = spf[x];
            union(v, p);
            while (x % p === 0) x = Math.floor(x / p);
        }
    }
    const sortedNums = nums.slice().sort((a, b) => a - b);
    for (let i = 0; i < nums.length; i++) {
        if (find(nums[i]) !== find(sortedNums[i])) return false;
    }
    return true;
};
